mapper.select:
SELECT * FROM customer_t
WHERE active = 0

    AND grade = #{grade}

ORDER BY c_idx DESC
LIMIT #{numPerPage} OFFSET #{offset}

mapper.update:
UPDATE customer_t
SET name  = #{name},
    phone = #{phone},
    grade = #{grade},
    memo  = #{memo}
WHERE c_idx = #{c_idx}

mapper.select:
SELECT * FROM customer_t
WHERE active = 0
  AND (name LIKE #{keyword} OR phone LIKE #{keyword})

    AND grade = #{grade}

ORDER BY c_idx DESC
LIMIT #{numPerPage} OFFSET #{offset}
